        // 6. Unregister batch
        graph.unregisterBatch(batch_id);

        // 7. Verify nodes are no longer in batch
        for (const auto& node : nodes) {
            if (graph.isInBatch(node, batch_id)) {
                return false;
            }
        }

        // 8. Return success status
        return true;
    }
    catch (const std::exception& e) {
        // Handle any exceptions and return false
        return false;
    }
}

}  // namespace test_reaction
