 * @return std::string Combined string of retrieved names
 */
std::string test_named_reactions(int valueA, int valueB) {
    // Create reactive variables with names
    auto varA = rv::Var<int>::create(valueA, "varA");
    auto varB = rv::Var<int>::create(valueB, "varB");

    // Create calculation with name that depends on the reactive variables
    auto calc = rv::Calc<int>::create(
        [varA, varB]() { return varA->get() + varB->get(); },
        "sum_calculation"
    );

    // Create action with name that modifies the reactive variables
    auto action = rv::Action::create(
        [varA, varB]() {
            varA->set(varA->get() + 1);
            varB->set(varB->get() - 1);
        },
        "increment_decrement_action"
    );

    // Retrieve names
    std::string varAName = varA->getName();
    std::string varBName = varB->getName();
    std::string calcName = calc->getName();
    std::string actionName = action->getName();

    // Return combined names string
    return varAName + "," + varBName + "," + calcName + "," + actionName;
}

}  // namespace test_reaction
