#pragma once

#include <reaction/reaction.h>

namespace test_reaction {

class CacheProbeNode : public reaction::ObserverNode {
public:
    void valueChanged(bool changed = true) override {
        // Default implementation - does nothing
        // This can be overridden by derived classes if needed
        (void)changed;
    }
};

struct CacheStatsSnapshot {
    size_t graphEntriesBeforeCleanup;
    size_t graphEntriesAfterCleanup;
    double graphHitRatioAfterCleanup;
};

CacheStatsSnapshot test_observer_cache_stats() {
    // 1. Create CacheProbeNode instances
    auto node1 = std::make_shared<CacheProbeNode>();
    auto node2 = std::make_shared<CacheProbeNode>();
    auto node3 = std::make_shared<CacheProbeNode>();
    auto node4 = std::make_shared<CacheProbeNode>();

    // 2. Get observer graph instance
    auto& graph = reaction::ObserverGraph::getInstance();

    // 3. Register nodes
    graph.registerNode(node1);
    graph.registerNode(node2);
    graph.registerNode(node3);
    graph.registerNode(node4);

    // 4. Set up direct observer relationship
    graph.addObserver(node2, node1); // node2 observes node1
    graph.addObserver(node3, node2); // node3 observes node2

    // 5. Set up transitive observer relationship
    graph.addObserver(node4, node3); // node4 observes node3 (transitive through node2)

    // 6. Create NodeSet to store collected observers
    reaction::NodeSet collectedObservers;

    // 7. Populate cache data by querying observers multiple times
    for (int i = 0; i < 10; ++i) {
        graph.getObservers(node1, collectedObservers);
        graph.getObservers(node2, collectedObservers);
        graph.getObservers(node3, collectedObservers);
        collectedObservers.clear();
    }

    // 8. Get cache statistics before cleanup
    auto cacheStats = graph.getCacheStatistics();
    size_t graphEntriesBeforeCleanup = cacheStats.entryCount;

    // 9. Trigger cache cleanup
    graph.cleanupCache();

    // 10. Get cache statistics after cleanup
    cacheStats = graph.getCacheStatistics();
    size_t graphEntriesAfterCleanup = cacheStats.entryCount;
    double graphHitRatioAfterCleanup = cacheStats.hitRatio;

    // 11. Close all nodes
    graph.unregisterNode(node1);
    graph.unregisterNode(node2);
    graph.unregisterNode(node3);
    graph.unregisterNode(node4);

    // 12. Return cache stats snapshot
    return CacheStatsSnapshot{
        graphEntriesBeforeCleanup,
        graphEntriesAfterCleanup,
        graphHitRatioAfterCleanup
    };
}

}  // namespace test_reaction
