    // Create reactive variable with Counter
    auto counter_var = reaction::make_react_var(Counter{initialValue});

    // Get first pointer
    auto ptr1 = reaction::get_pointer(counter_var);

    // Call add method through pointer
    ptr1->add(delta);

    // Get current value after first add
    int first_value = ptr1->value;

    // Get second pointer
    auto ptr2 = reaction::get_pointer(counter_var);

    // Call add method through pointer again
    ptr2->add(delta);

    // Get current value after second add
    int second_value = ptr2->value;

