    source1->attachObserver(observer);

    // Trigger notification on first source
    source1->notifyObservers();

    // Get notification count after initial setup
    int firstNotificationsAfterInitial = observer->notifications();

    // Rewire dependencies
    source1->detachObserver(observer);
    source2->attachObserver(observer);

    // Trigger notification on old source
    source1->notifyObservers();

    // Get notification count after old source notification
    int firstNotificationsAfterUpdate = observer->notifications();

    // Trigger notification on second source
    source2->notifyObservers();

