inline LogicalExpressionSnapshot test_logical_expression_builders(bool a, bool b, bool c) {
    // Create reactive boolean variables
    auto ra = reaction::var(a);
    auto rb = reaction::var(b);
    auto rc = reaction::var(c);

    // Build logical AND expression using && operator
    auto and_expr = reaction::expr([ra, rb]() { return ra && rb; });

    // Build logical OR expression using || operator  
    auto or_expr = reaction::expr([ra, rc]() { return ra || rc; });

    // Get initial AND and OR results
    bool initialAnd = and_expr.get();
